import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void basicMixed() {
        assertArrayEquals(
            new int[]{0, 1, 9, 16, 100},
            new Solution().sortedSquares(new int[]{-4, -1, 0, 3, 10})
        );
    }

    @Test
    void allNegative() {
        assertArrayEquals(
            new int[]{1, 4, 9, 16},
            new Solution().sortedSquares(new int[]{-4, -3, -2, -1})
        );
    }

    @Test
    void allPositive() {
        assertArrayEquals(
            new int[]{1, 4, 9, 16, 25},
            new Solution().sortedSquares(new int[]{1, 2, 3, 4, 5})
        );
    }

    @Test
    void single() {
        assertArrayEquals(
            new int[]{9},
            new Solution().sortedSquares(new int[]{-3})
        );
    }

    @Test
    void empty() {
        assertArrayEquals(
            new int[]{},
            new Solution().sortedSquares(new int[]{})
        );
    }

    @Test
    void symmetricAroundZero() {
        // adversarial: both ends have equal absolute value
        assertArrayEquals(
            new int[]{0, 1, 1, 4, 4, 9, 9},
            new Solution().sortedSquares(new int[]{-3, -2, -1, 0, 1, 2, 3})
        );
    }

    @Test
    void containsZero() {
        assertArrayEquals(
            new int[]{0, 1, 25},
            new Solution().sortedSquares(new int[]{-5, 0, 1})
        );
    }
}
